import requests

# Kong Admin API endpoint
admin_url = "http://kong:8001/admin/"

# Services
services = [
    {"name": "service1", "url": "example.com"},
    {"name": "service2", "url": "another.com"},
]

# Routes
routes = [
    {
        "name": "route1",
        "service": "service1",
        "paths": ["/path1"],
        "methods": ["GET"],
    },
    {
        "name": "route2",
        "service": "service2",
        "paths": ["/path2"],
        "methods": ["POST"],
    },
]

# Upstream targets
upstreams = [
    {
        "name": "upstream1",
        "targets": ["target1.com:80", "target2.com:80"],
        "healthcheck": {"path": "/healthcheck"},
    },
    {
        "name": "upstream2",
        "targets": ["target3.com:80", "target4.com:80"],
        "healthcheck": {"path": "/healthcheck"},
    },
]

# Create services
for service in services:
    response = requests.post(admin_url + "services", json=service)

# Create routes
for route in routes:
    response = requests.post(admin_url + "routes", json=route)

# Create upstream targets
for upstream in upstreams:
    response = requests.post(admin_url + "upstreams", json=upstream)